// wrangler.toml configuration for public-api-worker:
/*
name = "public-api-worker"
main = "public-api-worker.js"
compatibility_date = "2024-01-01"

[[services]]
binding = "AUTH_SERVICE"
service = "auth-worker"

[[services]]
binding = "DATA_SERVICE"
service = "data-worker"

[[services]]
binding = "ANALYTICS_SERVICE"
service = "analytics-worker"

[vars]
ALLOWED_ORIGINS = "https://yourdomain.com,https://app.yourdomain.com"
MAX_REQUEST_SIZE = "10485760"
RATE_LIMIT_REQUESTS = "100"
RATE_LIMIT_WINDOW = "60"
*/

const ALLOWED_METHODS = ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'];
const ALLOWED_PATHS = ['/api/auth', '/api/data', '/api/analytics'];
const MAX_PATH_LENGTH = 256;
const MAX_HEADER_VALUE_LENGTH = 4096;

class SecurityValidator {
  static validateMethod(method) {
    if (!ALLOWED_METHODS.includes(method.toUpperCase())) {
      throw new Error('Method not allowed');
    }
  }

  static validatePath(path) {
    if (!path || typeof path !== 'string') {
      throw new Error('Invalid path');
    }
    
    if (path.length > MAX_PATH_LENGTH) {
      throw new Error('Path too long');
    }

    if (path.includes('..') || path.includes('//')) {
      throw new Error('Path traversal detected');
    }

    const normalizedPath = new URL(path, 'https://dummy.com').pathname;
    const isAllowed = ALLOWED_PATHS.some(allowed => 
      normalizedPath === allowed || normalizedPath.startsWith(allowed + '/')
    );

    if (!isAllowed) {
      throw new Error('Path not allowed');
    }

    return normalizedPath;
  }

  static validateHeaders(headers) {
    const dangerousHeaders = ['x-forwarded-for', 'x-real-ip', 'x-original-url'];
    
    for (const [key, value] of headers.entries()) {
      if (value.length > MAX_HEADER_VALUE_LENGTH) {
        throw new Error('Header value too long');
      }

      if (dangerousHeaders.includes(key.toLowerCase())) {
        headers.delete(key);
      }
    }

    return headers;
  }

  static async validateRequestSize(request, maxSize) {
    const contentLength = request.headers.get('content-length');
    if (contentLength && parseInt(contentLength) > maxSize) {
      throw new Error('Request body too large');
    }
  }

  static validateOrigin(origin, allowedOrigins) {
    if (!origin) return false;
    
    const allowed = allowedOrigins.split(',').map(o => o.trim());
    return allowed.includes(origin);
  }

  static sanitizeLogData(data) {
    const sensitive = ['authorization', 'cookie', 'password', 'token', 'secret', 'api-key', 'api_key'];
    const sanitized = { ...data };
    
    for (const key in sanitized) {
      if (sensitive.some(s => key.toLowerCase().includes(s))) {
        sanitized[key] = '[REDACTED]';
      }
    }
    
    return sanitized;
  }
}

class RateLimiter {
  constructor(kv) {
    this.kv = kv;
  }

  async checkLimit(identifier, limit, windowSeconds) {
    if (!this.kv) return true;

    const key = `ratelimit:${identifier}`;
    const now = Math.floor(Date.now() / 1000);
    const windowKey = `${key}:${Math.floor(now / windowSeconds)}`;

    try {
      const count = await this.kv.get(windowKey);
      const currentCount = count ? parseInt(count) : 0;

      if (currentCount >= limit) {
        return false;
      }

      await this.kv.put(windowKey, (currentCount + 1).toString(), {
        expirationTtl: windowSeconds * 2
      });

      return true;
    } catch (error) {
      console.error('Rate limit check failed:', SecurityValidator.sanitizeLogData({ error: error.message }));
      return true;
    }
  }
}

async function handleRequest(request, env) {
  const requestId = crypto.randomUUID();
  const startTime = Date.now();

  try {
    SecurityValidator.validateMethod(request.method);
    
    const url = new URL(request.url);
    const path = SecurityValidator.validatePath(url.pathname);
    
    await SecurityValidator.validateRequestSize(
      request, 
      parseInt(env.MAX_REQUEST_SIZE || '10485760')
    );

    const origin = request.headers.get('origin');
    if (origin && !SecurityValidator.validateOrigin(origin, env.ALLOWED_ORIGINS || '')) {
      return new Response('Origin not allowed', { status: 403 });
    }

    const clientIp = request.headers.get('cf-connecting-ip') || 'unknown';
    const rateLimiter = new RateLimiter(env.RATE_LIMIT_KV);
    const isAllowed = await rateLimiter.checkLimit(
      clientIp,
      parseInt(env.RATE_LIMIT_REQUESTS || '100'),
      parseInt(env.RATE_LIMIT_WINDOW || '60')
    );

    if (!isAllowed) {
      return new Response('Rate limit exceeded', { status: 429 });
    }

    const sanitizedHeaders = SecurityValidator.validateHeaders(new Headers(request.headers));
    sanitizedHeaders.set('x-request-id', requestId);
    sanitizedHeaders.set('x-forwarded-proto', 'https');

    let targetService;
    let servicePath = path;

    if (path.startsWith('/api/auth')) {
      targetService = env.AUTH_SERVICE;
      servicePath = path.replace('/api/auth', '');
    } else if (path.startsWith('/api/data')) {
      targetService = env.DATA_SERVICE;
      servicePath = path.replace('/api/data', '');
    } else if (path.startsWith('/api/analytics')) {
      targetService = env.ANALYTICS_SERVICE;
      servicePath = path.replace('/api/analytics', '');
    } else {
      return new Response('Service not found', { status: 404 });
    }

    if (!targetService) {
      return new Response('Service binding not configured', { status: 503 });
    }

    const serviceUrl = new URL(servicePath || '/', 'https://internal');
    serviceUrl.search = url.search;

    const serviceRequest = new Request(serviceUrl.toString(), {
      method: request.method,
      headers: sanitizedHeaders,
      body: request.method !== 'GET' && request.method !== 'HEAD' ? request.body : null
    });

    const response = await targetService.fetch(serviceRequest);
    
    const responseHeaders = new Headers(response.headers);
    responseHeaders.set('x-request-id', requestId);
    responseHeaders.set('x-content-type-options', 'nosniff');
    responseHeaders.set('x-frame-options', 'DENY');
    responseHeaders.set('x-xss-protection', '1; mode=block');
    responseHeaders.set('strict-transport-security', 'max-age=31536000; includeSubDomains');
    
    if (origin && SecurityValidator.validateOrigin(origin, env.ALLOWED_ORIGINS || '')) {
      responseHeaders.set('access-control-allow-origin', origin);
      responseHeaders.set('access-control-allow-credentials', 'true');
    }

    console.log(JSON.stringify(SecurityValidator.sanitizeLogData({
      requestId,
      method: request.method,
      path,
      status: response.status,
      duration: Date.now() - startTime
    })));

    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: responseHeaders
    });

  } catch (error) {
    console.error(JSON.stringify(SecurityValidator.sanitizeLogData({
      requestId,
      error: error.message,
      duration: Date.now() - startTime
    })));

    return new Response('Internal server error', { 
      status: error.message.includes('not allowed') || error.message.includes('detected') ? 400 : 500,
      headers: {
        'x-request-id': requestId,
        'content-type': 'text/plain'
      }
    });
  }
}

export default {
  async fetch(request, env, ctx) {
    if (request.method === 'OPTIONS') {
      const origin = request.headers.get('origin');
      if (origin && SecurityValidator.validateOrigin(origin, env.ALLOWED_ORIGINS || '')) {
        return new Response(null, {
          status: 204,
          headers: {
            'access-control-allow-origin': origin,
            'access-control-allow-methods': 'GET, POST, PUT, DELETE, PATCH',
            'access-control-allow-headers': 'content-type, authorization',
            'access-control-max-age': '86400'
          }
        });
      }
      return new Response(null, { status: 204 });
    }

    return handleRequest(request, env);
  }
};


