// wrangler.toml configuration for auth-worker:
/*
name = "auth-worker"
main = "auth-worker.js"
compatibility_date = "2024-01-01"

[vars]
JWT_ISSUER = "your-service"
TOKEN_EXPIRY_SECONDS = "3600"
*/

class AuthValidator {
  static validateCredentials(username, password) {
    if (!username || !password) {
      throw new Error('Missing credentials');
    }

    if (typeof username !== 'string' || typeof password !== 'string') {
      throw new Error('Invalid credential format');
    }

    if (username.length < 3 || username.length > 64) {
      throw new Error('Invalid username length');
    }

    if (password.length < 8 || password.length > 128) {
      throw new Error('Invalid password length');
    }

    const usernameRegex = /^[a-zA-Z0-9._@-]+$/;
    if (!usernameRegex.test(username)) {
      throw new Error('Invalid username format');
    }

    return { username, password };
  }

  static validateToken(token) {
    if (!token || typeof token !== 'string') {
      throw new Error('Invalid token');
    }

    if (token.length > 2048) {
      throw new Error('Token too long');
    }

    const parts = token.split('.');
    if (parts.length !== 3) {
      throw new Error('Invalid token format');
    }

    return token;
  }

  static async hashPassword(password, salt) {
    const encoder = new TextEncoder();
    const data = encoder.encode(password + salt);
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  }

  static async verifyPassword(password, hash, salt) {
    const computedHash = await this.hashPassword(password, salt);
    return computedHash === hash;
  }
}

class JWTHandler {
  static async generateToken(payload, secret, expirySeconds) {
    const header = {
      alg: 'HS256',
      typ: 'JWT'
    };

    const now = Math.floor(Date.now() / 1000);
    const tokenPayload = {
      ...payload,
      iat: now,
      exp: now + expirySeconds,
      jti: crypto.randomUUID()
    };

    const encodedHeader = this.base64UrlEncode(JSON.stringify(header));
    const encodedPayload = this.base64UrlEncode(JSON.stringify(tokenPayload));
    const signatureInput = `${encodedHeader}.${encodedPayload}`;

    const signature = await this.sign(signatureInput, secret);
    return `${signatureInput}.${signature}`;
  }

  static async verifyToken(token, secret) {
    const parts = token.split('.');
    if (parts.length !== 3) {
      throw new Error('Invalid token structure');
    }

    const [encodedHeader, encodedPayload, signature] = parts;
    const signatureInput = `${encodedHeader}.${encodedPayload}`;

    const expectedSignature = await this.sign(signatureInput, secret);
    if (signature !== expectedSignature) {
      throw new Error('Invalid signature');
    }

    const payload = JSON.parse(this.base64UrlDecode(encodedPayload));
    const now = Math.floor(Date.now() / 1000);

    if (payload.exp && payload.exp < now) {
      throw new Error('Token expired');
    }

    if (payload.nbf && payload.nbf > now) {
      throw new Error('Token not yet valid');
    }

    return payload;
  }

  static async sign(data, secret) {
    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signature = await crypto.subtle.sign(
      'HMAC',
      key,
      encoder.encode(data)
    );

    return this.base64UrlEncode(signature);
  }

  static base64UrlEncode(data) {
    let base64;
    if (typeof data === 'string') {
      base64 = btoa(data);
    } else {
      const bytes = new Uint8Array(data);
      const binary = String.fromCharCode(...bytes);
      base64 = btoa(binary);
    }
    return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
  }

  static base64UrlDecode(data) {
    let base64 = data.replace(/-/g, '+').replace(/_/g, '/');
    while (base64.length % 4) {
      base64 += '=';
    }
    return atob(base64);
  }
}

async function handleAuthRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;

  try {
    if (path === '/login' && request.method === 'POST') {
      const body = await request.json();
      const { username, password } = AuthValidator.validateCredentials(
        body.username,
        body.password
      );

      const userKey = `user:${username}`;
      const userData = await env.AUTH_KV?.get(userKey, { type: 'json' });

      if (!userData) {
        await new Promise(resolve => setTimeout(resolve, 100 + Math.random() * 200));
        return new Response(JSON.stringify({ error: 'Invalid credentials' }), {
          status: 401,
          headers: { 'content-type': 'application/json' }
        });
      }

      const isValid = await AuthValidator.verifyPassword(
        password,
        userData.passwordHash,
        userData.salt
      );

      if (!isValid) {
        return new Response(JSON.stringify({ error: 'Invalid credentials' }), {
          status: 401,
          headers: { 'content-type': 'application/json' }
        });
      }

      const jwtSecret = env.JWT_SECRET;
      if (!jwtSecret) {
        throw new Error('JWT secret not configured');
      }

      const token = await JWTHandler.generateToken(
        {
          sub: userData.id,
          username: userData.username,
          roles: userData.roles || []
        },
        jwtSecret,
        parseInt(env.TOKEN_EXPIRY_SECONDS || '3600')
      );

      return new Response(JSON.stringify({ 
        token,
        expiresIn: parseInt(env.TOKEN_EXPIRY_SECONDS || '3600')
      }), {
        status: 200,
        headers: { 'content-type': 'application/json' }
      });

    } else if (path === '/verify' && request.method === 'POST') {
      const authHeader = request.headers.get('authorization');
      if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return new Response(JSON.stringify({ error: 'Missing token' }), {
          status: 401,
          headers: { 'content-type': 'application/json' }
        });
      }

      const token = authHeader.substring(7);
      AuthValidator.validateToken(token);

      const jwtSecret = env.JWT_SECRET;
      if (!jwtSecret) {
        throw new Error('JWT secret not configured');
      }

      const payload = await JWTHandler.verifyToken(token, jwtSecret);

      return new Response(JSON.stringify({ 
        valid: true,
        user: {
          id: payload.sub,
          username: payload.username,
          roles: payload.roles
        }
      }), {
        status: 200,
        headers: { 'content-type': 'application/json' }
      });

    } else {
      return new Response(JSON.stringify({ error: 'Not found' }), {
        status: 404,
        headers: { 'content-type': 'application/json' }
      });
    }

  } catch (error) {
    console.error('Auth error:', SecurityValidator.sanitizeLogData({ error: error.message }));
    
    return new Response(JSON.stringify({ 
      error: error.message.includes('credentials') || error.message.includes('token') 
        ? error.message 
        : 'Authentication failed' 
    }), {
      status: error.message.includes('expired') ? 401 : 400,
      headers: { 'content-type': 'application/json' }
    });
  }
}

export default {
  async fetch(request, env, ctx) {
    return handleAuthRequest(request, env);
  }
};


