// DATA WORKER (data-worker)
// ============================================================================

// wrangler.toml configuration for data-worker:
/*
name = "data-worker"
main = "data-worker.js"
compatibility_date = "2024-01-01"

[[services]]
binding = "AUTH_SERVICE"
service = "auth-worker"

[vars]
MAX_QUERY_RESULTS = "100"
*/

class DataValidator {
  static validateId(id) {
    if (!id || typeof id !== 'string') {
      throw new Error('Invalid ID');
    }

    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(id)) {
      throw new Error('Invalid ID format');
    }

    return id;
  }

  static validateDataObject(data) {
    if (!data || typeof data !== 'object') {
      throw new Error('Invalid data object');
    }

    const jsonString = JSON.stringify(data);
    if (jsonString.length > 1048576) {
      throw new Error('Data object too large');
    }

    const allowedKeys = ['name', 'description', 'metadata', 'tags', 'status'];
    for (const key in data) {
      if (!allowedKeys.includes(key)) {
        throw new Error(`Invalid field: ${key}`);
      }

      if (typeof data[key] === 'string' && data[key].length > 10000) {
        throw new Error(`Field ${key} too long`);
      }
    }

    return data;
  }

  static validateQueryParams(params) {
    const validated = {};

    if (params.limit) {
      const limit = parseInt(params.limit);
      if (isNaN(limit) || limit < 1 || limit > 100) {
        throw new Error('Invalid limit parameter');
      }
      validated.limit = limit;
    }

    if (params.offset) {
      const offset = parseInt(params.offset);
      if (isNaN(offset) || offset < 0) {
        throw new Error('Invalid offset parameter');
      }
      validated.offset = offset;
    }

    if (params.filter) {
      if (typeof params.filter !== 'string' || params.filter.length > 256) {
        throw new Error('Invalid filter parameter');
      }
      validated.filter = params.filter;
    }

    return validated;
  }
}

async function verifyAuthentication(request, env) {
  const authHeader = request.headers.get('authorization');
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    throw new Error('Missing authentication');
  }

  if (!env.AUTH_SERVICE) {
    throw new Error('Auth service not available');
  }

  const verifyRequest = new Request('https://internal/verify', {
    method: 'POST',
    headers: {
      'authorization': authHeader,
      'content-type': 'application/json'
    }
  });

  const response = await env.AUTH_SERVICE.fetch(verifyRequest);
  if (!response.ok) {
    throw new Error('Authentication failed');
  }

  const result = await response.json();
  return result.user;
}

async function handleDataRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;

  try {
    const user = await verifyAuthentication(request, env);

    if (path === '/items' && request.method === 'GET') {
      const params = Object.fromEntries(url.searchParams);
      const validated = DataValidator.validateQueryParams(params);

      const limit = validated.limit || 10;
      const offset = validated.offset || 0;

      const items = [];
      const list = await env.DATA_KV?.list({ 
        prefix: 'item:',
        limit: limit
      });

      if (list) {
        for (const key of list.keys) {
          const item = await env.DATA_KV.get(key.name, { type: 'json' });
          if (item) {
            items.push(item);
          }
        }
      }

      return new Response(JSON.stringify({ 
        items,
        total: items.length,
        limit,
        offset
      }), {
        status: 200,
        headers: { 'content-type': 'application/json' }
      });

    } else if (path.startsWith('/items/') && request.method === 'GET') {
      const id = DataValidator.validateId(path.split('/')[2]);
      
      const item = await env.DATA_KV?.get(`item:${id}`, { type: 'json' });
      if (!item) {
        return new Response(JSON.stringify({ error: 'Item not found' }), {
          status: 404,
          headers: { 'content-type': 'application/json' }
        });
      }

      return new Response(JSON.stringify(item), {
        status: 200,
        headers: { 'content-type': 'application/json' }
      });

    } else if (path === '/items' && request.method === 'POST') {
      const body = await request.json();
      const data = DataValidator.validateDataObject(body);

      const id = crypto.randomUUID();
      const item = {
        id,
        ...data,
        createdBy: user.id,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
      };

      await env.DATA_KV?.put(`item:${id}`, JSON.stringify(item));

      return new Response(JSON.stringify(item), {
        status: 201,
        headers: { 'content-type': 'application/json' }
      });

    } else if (path.startsWith('/items/') && request.method === 'PUT') {
      const id = DataValidator.validateId(path.split('/')[2]);
      const body = await request.json();
      const data = DataValidator.validateDataObject(body);

      const existing = await env.DATA_KV?.get(`item:${id}`, { type: 'json' });
      if (!existing) {
        return new Response(JSON.stringify({ error: 'Item not found' }), {
          status: 404,
          headers: { 'content-type': 'application/json' }
        });
      }

      if (existing.createdBy !== user.id && !user.roles.includes('admin')) {
        return new Response(JSON.stringify({ error: 'Forbidden' }), {
          status: 403,
          headers: { 'content-type': 'application/json' }
        });
      }

      const item = {
        ...existing,
        ...data,
        updatedAt: new Date().toISOString()
      };

      await env.DATA_KV?.put(`item:${id}`, JSON.stringify(item));

      return new Response(JSON.stringify(item), {
        status: 200,
        headers: { 'content-type': 'application/json' }
      });

    } else if (path.startsWith('/items/') && request.method === 'DELETE') {
      const id = DataValidator.validateId(path.split('/')[2]);

      const existing = await env.DATA_KV?.get(`item:${id}`, { type: 'json' });
      if (!existing) {
        return new Response(JSON.stringify({ error: 'Item not found' }), {
          status: 404,
          headers: { 'content-type': 'application/json' }
        });
      }

      if (existing.createdBy !== user.id && !user.roles.includes('admin')) {
        return new Response(JSON.stringify({ error: 'Forbidden' }), {
          status: 403,
          headers: { 'content-type': 'application/json' }
        });
      }

      await env.DATA_KV?.delete(`item:${id}`);

      return new Response(null, { status: 204 });

    } else {
      return new Response(JSON.stringify({ error: 'Not found' }), {
        status: 404,
        headers: { 'content-type': 'application/json' }
      });
    }

  } catch (error) {
    console.error('Data error:', SecurityValidator.sanitizeLogData({ error: error.message }));

    const status = error.message.includes('Authentication') ? 401 :
                   error.message.includes('Forbidden') ? 403 :
                   error.message.includes('not found') ? 404 : 400;

    return new Response(JSON.stringify({ error: error.message }), {
      status,
      headers: { 'content-type': 'application/json' }
    });
  }
}

export default {
  async fetch(request, env, ctx) {
    return handleDataRequest(request, env);
  }
};


