// ANALYTICS WORKER (analytics-worker)
// ============================================================================

// wrangler.toml configuration for analytics-worker:
/*
name = "analytics-worker"
main = "analytics-worker.js"
compatibility_date = "2024-01-01"

[[services]]
binding = "AUTH_SERVICE"
service = "auth-worker"

[vars]
MAX_EVENTS_PER_REQUEST = "100"
*/

class AnalyticsValidator {
  static validateEvent(event) {
    if (!event || typeof event !== 'object') {
      throw new Error('Invalid event object');
    }

    const requiredFields = ['type', 'timestamp'];
    for (const field of requiredFields) {
      if (!event[field]) {
        throw new Error(`Missing required field: ${field}`);
      }
    }

    const allowedTypes = ['pageview', 'click', 'conversion', 'error', 'custom'];
    if (!allowedTypes.includes(event.type)) {
      throw new Error('Invalid event type');
    }

    if (typeof event.timestamp !== 'number' || event.timestamp < 0) {
      throw new Error('Invalid timestamp');
    }

    const now = Date.now();
    if (event.timestamp > now + 60000 || event.timestamp < now - 86400000) {
      throw new Error('Timestamp out of acceptable range');
    }

    if (event.properties) {
      const propsString = JSON.stringify(event.properties);
      if (propsString.length > 10000) {
        throw new Error('Event properties too large');
      }
    }

    return event;
  }

  static validateEventBatch(events) {
    if (!Array.isArray(events)) {
      throw new Error('Events must be an array');
    }

    if (events.length === 0) {
      throw new Error('Empty event batch');
    }

    if (events.length > 100) {
      throw new Error('Too many events in batch');
    }

    return events.map(event => this.validateEvent(event));
  }

  static validateTimeRange(start, end) {
    const startTime = parseInt(start);
    const endTime = parseInt(end);

    if (isNaN(startTime) || isNaN(endTime)) {
      throw new Error('Invalid time range');
    }

    if (startTime < 0 || endTime < 0) {
      throw new Error('Invalid time range');
    }

    if (startTime > endTime) {
      throw new Error('Start time must be before end time');
    }

    const maxRange = 30 * 24 * 60 * 60 * 1000;
    if (endTime - startTime > maxRange) {
      throw new Error('Time range too large');
    }

    return { start: startTime, end: endTime };
  }
}

async function handleAnalyticsRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;

  try {
    const user = await verifyAuthentication(request, env);

    if (path === '/events' && request.method === 'POST') {
      const body = await request.json();
      const events = AnalyticsValidator.validateEventBatch(body.events || [body]);

      const enrichedEvents = events.map(event => ({
        ...event,
        userId: user.id,
        receivedAt: Date.now(),
        id: crypto.randomUUID()
      }));

      for (const event of enrichedEvents) {
        const key = `event:${event.userId}:${event.id}`;
        await env.ANALYTICS_KV?.put(key, JSON.stringify(event), {
          expirationTtl: 90 * 24 * 60 * 60
        });
      }

      return new Response(JSON.stringify({ 
        success: true,
        processed: enrichedEvents.length
      }), {
        status: 201,
        headers: { 'content-type': 'application/json' }
      });

    } else if (path === '/events' && request.method === 'GET') {
      const start = url.searchParams.get('start');
      const end = url.searchParams.get('end');

      if (!start || !end) {
        throw new Error('Missing time range parameters');
      }

      const timeRange = AnalyticsValidator.validateTimeRange(start, end);

      const events = [];
      const list = await env.ANALYTICS_KV?.list({ 
        prefix: `event:${user.id}:`,
        limit: 1000
      });

      if (list) {
        for (const key of list.keys) {
          const event = await env.ANALYTICS_KV.get(key.name, { type: 'json' });
          if (event && event.timestamp >= timeRange.start && event.timestamp <= timeRange.end) {
            events.push(event);
          }
        }
      }

      return new Response(JSON.stringify({ 
        events,
        count: events.length
      }), {
        status: 200,
        headers: { 'content-type': 'application/json' }
      });

    } else if (path === '/stats' && request.method === 'GET') {
      const start = url.searchParams.get('start');
      const end = url.searchParams.get('end');

      if (!start || !end) {
        throw new Error('Missing time range parameters');
      }

      const timeRange = AnalyticsValidator.validateTimeRange(start, end);

      const stats = {
        totalEvents: 0,
        eventsByType: {},
        timeRange: timeRange
      };

      const list = await env.ANALYTICS_KV?.list({ 
        prefix: `event:${user.id}:`,
        limit: 1000
      });

      if (list) {
        for (const key of list.keys) {
          const event = await env.ANALYTICS_KV.get(key.name, { type: 'json' });
          if (event && event.timestamp >= timeRange.start && event.timestamp <= timeRange.end) {
            stats.totalEvents++;
            stats.eventsByType[event.type] = (stats.eventsByType[event.type] || 0) + 1;
          }
        }
      }

      return new Response(JSON.stringify(stats), {
        status: 200,
        headers: { 'content-type': 'application/json' }
      });

    } else {
      return new Response(JSON.stringify({ error: 'Not found' }), {
        status: 404,
        headers: { 'content-type': 'application/json' }
      });
    }

  } catch (error) {
    console.error('Analytics error:', SecurityValidator.sanitizeLogData({ error: error.message }));

    const status = error.message.includes('Authentication') ? 401 :
                   error.message.includes('Forbidden') ? 403 : 400;

    return new Response(JSON.stringify({ error: error.message }), {
      status,
      headers: { 'content-type': 'application/json' }
    });
  }
}

export default {
  async fetch(request, env, ctx) {
    return handleAnalyticsRequest(request, env);
  }
};